from dataclasses import dataclass, field
from enum import Enum

class MigrationComplexity(str, Enum):
    TRIVIAL   = "trivial"   # parameter rename; one-line change
    LOW       = "low"       # new endpoint; drop-in replacement
    MEDIUM    = "medium"    # behaviour change; adaptation required
    HIGH      = "high"      # architectural change; weeks of work

@dataclass
class AffectedConsumer:
    consumer_id: str
    consumer_name: str
    consumer_type: str       # "api_consumer" | "internal_team" | "end_user"
    monthly_call_volume: int
    uses_deprecated_feature: bool
    migration_complexity: MigrationComplexity
    contact_email: str
    has_acknowledged: bool = False

    def tier(self) -> str:
        if self.monthly_call_volume > 100_000:
            return "tier1"  # direct outreach required
        if self.monthly_call_volume > 1_000:
            return "tier2"  # email with migration guide
        return "tier3"      # changelog only

    def minimum_notice_days(self) -> int:
        mapping = {
            MigrationComplexity.HIGH:    90,
            MigrationComplexity.MEDIUM:  60,
            MigrationComplexity.LOW:     30,
            MigrationComplexity.TRIVIAL: 14,
        }
        return mapping[self.migration_complexity]

@dataclass
class SunsetScope:
    feature_name: str
    affected: list[AffectedConsumer] = field(default_factory=list)

    def max_notice_days_required(self) -> int:
        if not self.affected:
            return 14
        return max(c.minimum_notice_days() for c in self.affected)

    def by_tier(self, tier: str) -> list[AffectedConsumer]:
        return [c for c in self.affected if c.tier() == tier]

    def acknowledgement_rate(self) -> float:
        if not self.affected:
            return 1.0
        return sum(1 for c in self.affected if c.has_acknowledged) / len(self.affected)

from dataclasses import dataclass
from datetime import date

@dataclass
class AcknowledgementTracker:
    consumer_id: str
    last_deprecated_call_date: date | None   # from API telemetry; None if never used
    acknowledged_via_email: bool
    migration_confirmed: bool

    def is_migrated(self, today: date, grace_days: int = 7) -> bool:
        """
        A consumer is considered migrated if they have not called the
        deprecated endpoint in the last `grace_days` days.
        """
        if self.last_deprecated_call_date is None:
            return True
        return (today - self.last_deprecated_call_date).days > grace_days

    def escalation_required(self, today: date, days_until_eol: int) -> bool:
        if self.is_migrated(today):
            return False
        # Tier 1 consumers who haven't acknowledged with < 14 days left
        return days_until_eol < 14 and not self.acknowledged_via_email

    def status(self, today: date, days_until_eol: int) -> str:
        if self.is_migrated(today):
            return "migrated"
        if self.escalation_required(today, days_until_eol):
            return "escalation_required"
        return "in_progress"

from dataclasses import dataclass, field

@dataclass
class InternalReadinessChecklist:
    feature_name: str
    checks: dict[str, bool] = field(default_factory=dict)

    def mark_done(self, check: str) -> None:
        self.checks[check] = True

    def is_ready_to_publish(self) -> bool:
        required = {
            "migration_guide_published",
            "support_team_briefed",
            "account_team_notified_of_tier1_accounts",
            "api_deprecation_header_tested",
            "in_product_banner_deployed",
            "changelog_entry_drafted",
            "rollback_plan_documented",
        }
        return required.issubset(k for k, v in self.checks.items() if v)

    def missing_checks(self) -> list[str]:
        required = {
            "migration_guide_published",
            "support_team_briefed",
            "account_team_notified_of_tier1_accounts",
            "api_deprecation_header_tested",
            "in_product_banner_deployed",
            "changelog_entry_drafted",
            "rollback_plan_documented",
        }
        return sorted(required - {k for k, v in self.checks.items() if v})

    def publish_gate(self) -> str:
        missing = self.missing_checks()
        if not missing:
            return f"READY: all checks complete for {self.feature_name}"
        return f"NOT READY: {len(missing)} checks incomplete — {', '.join(missing[:3])}{'...' if len(missing) > 3 else ''}"

from dataclasses import dataclass
from datetime import date

@dataclass
class SunsetDocumentationRecord:
    feature_name: str
    eol_date: date
    original_doc_url: str
    migration_guide_url: str
    replacement_feature: str | None

    def api_reference_banner(self) -> str:
        replacement_note = (
            f" Use {self.replacement_feature} instead."
            if self.replacement_feature
            else " No direct replacement is available."
        )
        return (
            f"[REMOVED] {self.feature_name} was removed on "
            f"{self.eol_date.strftime('%B %d, %Y')}.{replacement_note} "
            f"See the migration guide: {self.migration_guide_url}"
        )

    def changelog_entry(self) -> str:
        return (
            f"**{self.eol_date.strftime('%Y-%m-%d')} — {self.feature_name} removed.** "
            f"This feature reached end-of-life after the 90-day deprecation window. "
            + (f"Replacement: {self.replacement_feature}. " if self.replacement_feature else "")
            + f"Migration guide available at {self.migration_guide_url}."
        )

    def redirect_target(self) -> str:
        if self.replacement_feature:
            return f"Redirect old doc URL to {self.replacement_feature} reference page"
        return "Redirect old doc URL to migration guide (no replacement reference)"

    def should_keep_migration_guide(self, years_since_eol: int) -> bool:
        # Migration guides remain searchable for 2 years post-EOL
        # to help consumers who encounter legacy code referencing the old feature.
        return years_since_eol < 2
